import{_ as e,c as o,o as a,ag as i}from"./chunks/framework.DD2hp6gW.js";const c=JSON.parse('{"title":"Installation & Setup","description":"","frontmatter":{},"headers":[],"relativePath":"installation.md","filePath":"installation.md","lastUpdated":1777110900000}'),n={name:"installation.md"};function s(r,t,l,d,u,g){return a(),o("div",null,t[0]||(t[0]=[i('<h1 id="installation-setup" tabindex="-1">Installation &amp; Setup <a class="header-anchor" href="#installation-setup" aria-label="Permalink to &quot;Installation &amp; Setup&quot;">​</a></h1><p>Getting started with <strong>OptionBay</strong> is simple and follows the standard WordPress plugin installation process. This guide will walk you through installing the plugin and ensuring your WooCommerce store is ready for custom product options.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before installing OptionBay, please ensure your site meets the following requirements:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Requirement</th><th style="text-align:left;">Minimum Version</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>WordPress</strong></td><td style="text-align:left;">5.6 or higher</td></tr><tr><td style="text-align:left;"><strong>WooCommerce</strong></td><td style="text-align:left;">6.1 or higher</td></tr><tr><td style="text-align:left;"><strong>PHP</strong></td><td style="text-align:left;">7.0 or higher</td></tr></tbody></table><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>OptionBay requires WooCommerce to be installed and activated. The plugin will not function without an active WooCommerce installation.</p></div><h2 id="installation-steps" tabindex="-1">Installation Steps <a class="header-anchor" href="#installation-steps" aria-label="Permalink to &quot;Installation Steps&quot;">​</a></h2><h3 id="_1-upload-and-activate" tabindex="-1">1. Upload and Activate <a class="header-anchor" href="#_1-upload-and-activate" aria-label="Permalink to &quot;1. Upload and Activate&quot;">​</a></h3><ol><li>Log in to your WordPress Admin Dashboard.</li><li>Navigate to <strong>Plugins &gt; Add New</strong>.</li><li>Click the <strong>Upload Plugin</strong> button at the top of the page.</li><li>Choose the <code>optionbay.zip</code> file from your computer and click <strong>Install Now</strong>.</li><li>Once the installation is complete, click <strong>Activate Plugin</strong>.</li></ol><h3 id="_2-verify-menu-access" tabindex="-1">2. Verify Menu Access <a class="header-anchor" href="#_2-verify-menu-access" aria-label="Permalink to &quot;2. Verify Menu Access&quot;">​</a></h3><p>After activation, you should see the following new entries in your WordPress admin:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Location</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Products &gt; Options</strong></td><td style="text-align:left;">Create and manage your Option Groups — this is where you build your forms.</td></tr><tr><td style="text-align:left;"><strong>WooCommerce &gt; Settings &gt; OptionBay</strong></td><td style="text-align:left;">Global display and performance settings for the plugin.</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If you don&#39;t see the &quot;Options&quot; menu under Products, try refreshing the page or clearing your browser cache. WordPress sometimes needs a hard refresh after plugin activation.</p></div><h2 id="initial-configuration" tabindex="-1">Initial Configuration <a class="header-anchor" href="#initial-configuration" aria-label="Permalink to &quot;Initial Configuration&quot;">​</a></h2><p>Once the plugin is activated, it&#39;s recommended to check the global settings to ensure the display matches your theme:</p><ol><li>Navigate to <strong>WooCommerce &gt; Settings</strong> and click on the <strong>OptionBay</strong> tab.</li><li>Configure your <strong>Options Orientation</strong> (Vertical or Horizontal) to match your product page layout.</li><li>Set your preferred <strong>Font Sizes</strong> for labels and inputs to align with your theme&#39;s typography.</li><li>If you plan to use swatches, configure the <strong>Swatch Size</strong> and <strong>Swatch Radius</strong> settings.</li><li>Save your changes using the native WooCommerce <strong>Save changes</strong> button at the bottom.</li></ol><h2 id="what-s-next" tabindex="-1">What&#39;s Next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next?&quot;">​</a></h2><p>Now that you&#39;ve installed OptionBay, you&#39;re ready to start building your first set of custom product options:</p><ol><li><strong><a href="./option-groups.html">Create an Option Group</a></strong> — Learn about the building blocks of OptionBay.</li><li><strong><a href="./builder.html">Build Your Fields</a></strong> — Use the drag-and-drop Addon Builder to add fields.</li><li><strong><a href="./assignments.html">Assign to Products</a></strong> — Configure rules to display your options on specific products or categories.</li></ol>',19)]))}const p=e(n,[["render",s]]);export{c as __pageData,p as default};
